//帮别人调
#include <bits/stdc++.h>
using namespace std;
int maxn2;
int count(string s) {
	int cnt=0;
	for(int i=0; i < s.length()-1; i++) {
		if(s[i] == 'V' && s[i+1] == 'K') {
			cnt++;
		}
	}
	return cnt;
}
int main() {
	int n;
	cin >> n;
	string s;
	cin >> s;
	int maxn = count(s);
	maxn2=maxn;
	for(int i=0; i < n; i++) {
		string m = s;
		if(m[i] == 'V') m[i] = 'K';
		else if(m[i] == 'K') m[i] = 'V';

		maxn2 = max(maxn2,count(m));
	}
	cout << maxn2;
}
